const context = @import("core/context.zig");
const errmod = @import("core/error.zig");

pub const ProjectNameSDK = sdk.ProjectNameSDK;
// Non-branded alias so target-agnostic tests need no name substitution.
pub const SDK = sdk.ProjectNameSDK;
pub const test_sdk = sdk.test_sdk;

pub const Value = helpers.Value;
pub const OpResult = types.OpResult;
pub const Feature = types.Feature;
pub const OutVal = types.OutVal;
pub const Context = context.Context;
pub const CtxSpec = context.CtxSpec;
pub const ProjectNameError = errmod.ProjectNameError;

// Internals exposed for the template test suite.
pub const types_mod = types;
pub const BaseFeature = @import("feature/base.zig").BaseFeature;

// Value helpers, re-exported so tests/consumers can build data.
pub const h = helpers;
pub const vs = @import("voxgig-struct");

// No-argument convenience constructors.
pub fn new() *ProjectNameSDK {
    return ProjectNameSDK.new(Value{ .null = {} });
}

pub fn testSdk() *ProjectNameSDK {
    return test_sdk(Value{ .null = {} }, Value{ .null = {} });
}
